=draft}} ) – {{ill|Ono Gohei|ja|小野五平|qq=|12=draft}} , 12th {{ill|Meijin (shogi)|ja|名人|qq=|12=draft}} in shogi. * {{ill|Tongzhi Emperor|ja|同治|qq=|12=draft}} 5 (Gregorian {{ill|1866|ja|1866th year|qq=|12=draft}} {{ill|November 12|ja|11月12日|qq=|12=draft}} ) – {{ill|Sun Yat-sen|ja|孫文|qq=|12=draft}} , revolutionary and first {{ill|Provisional President of the Republic of China|ja|中華民国大総統|qq=|12=draft}} (+ {{ill|1925|ja|1925th year|qq=|12=draft}} ). == Deaths == * {{ill|Tenshō (Japan)|ja|天正|1=Tenshō (Momoyama period)|lt=Tenshō Era|qq=|12=draft}} 12 (Gregorian {{ill|1584|ja|1584th year|qq=|12=draft}} {{ill|November 8|ja|11月8日|qq=|12=draft}} ) – {{ill|Ashina Moritaka|ja|蘆名盛隆|qq=|12=draft}} , {{ill|Sengoku daimyo|ja|戦国大名|qq=|12=draft}} (* {{ill|1561|ja|1561st year|qq=|12=draft}} ). * {{ill|Shōtoku (era)|ja|正徳|qq=|12=draft}} 5 (Gregorian {{ill|1715|ja|1715th year|qq=|12=draft}} {{ill|November 1|ja|11月1日|qq=|12=draft}} ) – {{ill|Shibukawa Harumi|ja|渋川春海|qq=|12=draft}} , also known as the 2nd {{ill|Yasui Santetsu|ja|安井算哲|qq=|12=draft}} , astronomer and calendrical scholar (* {{ill|1639|ja|1639th year|qq=|12=draft}} ). * {{ill|Enkyō (Japan)|ja|Enkyō|qq=|12=draft}} 4 (Gregorian {{ill|1747|ja|1747th year|qq=|12=draft}} {{ill|November 8|ja|11月8日|qq=|12=draft}} ) – {{ill|Terazaka Nobuyuki|ja|寺坂信行|qq=|12=draft}} , one of the {{ill|Forty-seven rōnin|ja|赤穂浪士|qq=|12=draft}} (* {{ill|1665|ja|1665th year|qq=|12=draft}} ). == Commemorations ==
